CREATE TABLE IF NOT EXISTS ai_alerts (id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY, event_id VARCHAR(128) NOT NULL, alert_type VARCHAR(100) NOT NULL, description TEXT NOT NULL, priority VARCHAR(20) NOT NULL, status VARCHAR(30) NOT NULL DEFAULT 'new', created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS idx_ai_alerts_priority ON ai_alerts(priority,status,created_at DESC);
